package tests;import base.BaseTest;import pages.CamareroPage;import pages.LoginPage;import org.junit.jupiter.api.Assertions;import org.junit.jupiter.api.Test;public class HP09GenerarCuentaTest extends BaseTest {    @Test    void generarCuentaCorrectamenteParaPedidoCompletado() {        try {            System.out.println("Ejecutando HP-09: Generar cuenta correctamente para pedido completado");            LoginPage loginPage = new LoginPage(driver);            loginPage.abrirLogin();            loginPage.iniciarSesion("camarero", "123");            Thread.sleep(3000);            CamareroPage camareroPage = new CamareroPage(driver);            Assertions.assertTrue(                    camareroPage.cantidadBotonesPreBoleta() > 0,                    "No existe ningún pedido entregado con opción Pre-Boleta."            );            camareroPage.abrirPreBoleta();            Thread.sleep(3000);            Assertions.assertTrue(                    camareroPage.detallePedidoVisible(),                    "No se visualiza el detalle del pedido."            );            Assertions.assertTrue(                    camareroPage.totalesVisibles(),                    "No se visualizan correctamente los totales de la cuenta."            );            Assertions.assertTrue(                    camareroPage.botonCompletarPagoVisible(),                    "No se visualiza el botón Completar Pago."            );            System.out.println("HP-09 ejecutado correctamente.");        } catch (Exception e) {            Assertions.fail("Error en HP-09: " + e.getMessage());        }    }}